SELECT * FROM nx_machine_alert_record


        AND nx_ar_device_id = #{deviceId}


        AND nx_ar_manager_id = #{managerId}


        AND nx_ar_is_cleared = #{isCleared}


        AND nx_ar_is_read = #{isRead}


ORDER BY nx_ar_create_time DESC

    LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM nx_machine_alert_record


        AND nx_ar_device_id = #{deviceId}


        AND nx_ar_manager_id = #{managerId}


        AND nx_ar_is_cleared = #{isCleared}

SELECT * FROM nx_machine_alert_record
WHERE nx_ar_device_id = #{deviceId}

    AND nx_ar_is_cleared = #{isCleared}

ORDER BY nx_ar_create_time DESC

    LIMIT #{offset}, #{limit}

SELECT ar.*, pd.nx_pd_id, pd.nx_pd_device_no, pd.nx_pd_device_name, pd.nx_pd_location
FROM nx_machine_alert_record ar
LEFT JOIN nx_machine_printer_device pd ON ar.nx_ar_device_id = pd.nx_pd_id
WHERE ar.nx_ar_manager_id = #{managerId}

    AND ar.nx_ar_is_cleared = #{isCleared}


    AND ar.nx_ar_is_read = #{isRead}


    AND ar.nx_ar_create_time >= DATE_SUB(NOW(), INTERVAL #{days} DAY)

ORDER BY ar.nx_ar_create_time DESC

    LIMIT #{offset}, #{limit}

SELECT * FROM nx_machine_alert_record
WHERE nx_ar_device_id = #{deviceId}
  AND nx_ar_alert_level = #{alertLevel}
  AND nx_ar_is_cleared = 0
ORDER BY nx_ar_create_time DESC
LIMIT 1

mapper.update:
UPDATE nx_machine_alert_record
nx_ar_send_status = #{nxArSendStatus}, nx_ar_is_cleared = #{nxArIsCleared}, nx_ar_is_read = #{nxArIsRead},
WHERE nx_ar_id = #{nxArId}
